// RUN: objc3c -x objective-c++ -fobjc-version=3 -fsyntax-only %s
typedef enum objc_async_completion_status {
    OBJC_ASYNC_COMPLETION_SUCCESS = 0,
    OBJC_ASYNC_COMPLETION_ERROR = 1,
    OBJC_ASYNC_COMPLETION_CANCELLED = 2
} objc_async_completion_status_t;

typedef struct INTCXX02Box {
    id _Nullable savedResult;
    id<Error> _Nullable savedError;
} INTCXX02Box;

void intcxx02_async_callback(void * _Nullable context,
                             objc_async_completion_status_t status,
                             id _Nullable result,
                             id<Error> _Nullable error) {
    INTCXX02Box *box = (INTCXX02Box *)context;
    box->savedResult = result;
    box->savedError = error;
    (void)status;
}
